+name: Weekly Coverage Review
+
+# Reviews the past week's hourly coverage runs.
+# Opens issues for: flaky tests, coverage regressions, areas needing hardening.
+
+on:
+  schedule:
+    - cron: '0 9 * * 1'  # Monday 9 AM UTC
+  workflow_dispatch:
+
+permissions:
+  contents: read
+  issues: write
+
+env:
+  REVIEW_DAYS: 7
+
+jobs:
+  weekly-review:
+    if: github.repository == 'kubestellar/console'
+    runs-on: ubuntu-latest
+    timeout-minutes: 10
+
+    steps:
+      - name: Checkout
+        uses: actions/checkout@v4
+
+      - name: Analyze past week's coverage runs
+        uses: actions/github-script@v7
+        with:
+          script: |
+            const REVIEW_DAYS = parseInt(process.env.REVIEW_DAYS || '7');
+            const since = new Date(Date.now() - REVIEW_DAYS * 24 * 60 * 60 * 1000).toISOString();
+
+            // Get hourly coverage workflow runs from past week
+            const { data: runs } = await github.rest.actions.listWorkflowRuns({
+              owner: context.repo.owner,
+              repo: context.repo.repo,
+              workflow_id: 'coverage-hourly.yml',
+              status: 'completed',
+              per_page: 100,
+              created: `>=${since.split('T')[0]}`,
+            });
+
+            const totalRuns = runs.workflow_runs.length;
+            const successful = runs.workflow_runs.filter(r => r.conclusion === 'success').length;
+            const failed = runs.workflow_runs.filter(r => r.conclusion === 'failure').length;
+            const cancelled = runs.workflow_runs.filter(r => r.conclusion === 'cancelled').length;
+            const successRate = totalRuns > 0 ? Math.round((successful / totalRuns) * 100) : 0;
+
+            console.log(`Past ${REVIEW_DAYS} days: ${totalRuns} runs, ${successful} success, ${failed} failed, ${cancelled} cancelled (${successRate}% success rate)`);
+
+            // Check for flaky pattern (> 10% failure rate)
+            const FLAKY_THRESHOLD = 10;
+            const failureRate = totalRuns > 0 ? Math.round((failed / totalRuns) * 100) : 0;
+
+            let issues = [];
+
+            if (failureRate > FLAKY_THRESHOLD) {
+              issues.push({
+                title: `[Coverage] ${failureRate}% test failure rate in past week (${failed}/${totalRuns} runs)`,
+                body: `## Weekly Coverage Review\n\n` +
+                  `The hourly coverage suite had a **${failureRate}% failure rate** this week.\n\n` +
+                  `| Metric | Value |\n|--------|-------|\n` +
+                  `| Total runs | ${totalRuns} |\n` +
+                  `| Successful | ${successful} |\n` +
+                  `| Failed | ${failed} |\n` +
+                  `| Cancelled | ${cancelled} |\n` +
+                  `| Success rate | ${successRate}% |\n\n` +
+                  `### Action needed\n` +
+                  `- [ ] Review failed run logs to identify flaky tests\n` +
+                  `- [ ] Harden or skip consistently failing tests\n` +
+                  `- [ ] Fix root cause of intermittent failures\n\n` +
+                  `_Auto-generated by Weekly Coverage Review_`,
+                labels: ['bug', 'help wanted', 'auto-qa'],
+              });
+            }
+
+            // Create issues if needed
+            for (const issue of issues) {
+              // Check for existing open issue with same title prefix
+              const { data: existing } = await github.rest.issues.listForRepo({
+                owner: context.repo.owner,
+                repo: context.repo.repo,
+                state: 'open',
+                labels: 'auto-qa',
+                per_page: 50,
+              });
+
+              const titlePrefix = issue.title.split(' in past')[0];
+              const duplicate = existing.find(e => e.title.includes('[Coverage]'));
+
+              if (!duplicate) {
+                await github.rest.issues.create({
+                  owner: context.repo.owner,
+                  repo: context.repo.repo,
+                  title: issue.title,
+                  body: issue.body,
+                  labels: issue.labels,
+                });
+                console.log(`Created issue: ${issue.title}`);
+              } else {
+                console.log(`Skipped duplicate: ${duplicate.title}`);
+              }
+            }
+
+            if (issues.length === 0) {
+              console.log(`All clear — ${successRate}% success rate is above ${FLAKY_THRESHOLD}% threshold`);
+            }
